package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import java.lang.foreign.MemorySegment;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

import org.apache.datasketches.common.MemorySegmentStatus;
import org.apache.datasketches.common.SketchesArgumentException;

/**
 * Base class for OmniSketch sketches.
 *
 * <p>
 * An OmniSketch models one dimension. Updating the sketch with {@code (value, identifier)} records allows later
 * estimation of the number of distinct identifiers matching equality or {@code IN} predicates over that dimension.
 * Multiple dimensions can be combined by estimating the intersection of per-dimension predicate summaries with
 * {@link OmniSketches#intersection(Iterable, Iterable)}.
 * </p>
 *
 * <p>
 * This class intentionally mirrors common DataSketches conventions: use {@link #builder()} to create heap update
 * sketches, {@link #compact()} to obtain an immutable compact form, {@link #heapify(MemorySegment)} to copy a
 * serialized compact image to the Java heap, and {@link #wrap(MemorySegment)} to access a compact image directly from
 * caller-owned memory.
 * </p>
 */
public abstract class OmniSketch implements MemorySegmentStatus {
	OmniSketch() {
	}

	/** Returns a new builder for heap update OmniSketches and OmniSketch unions. */
	public static OmniSketchBuilder builder() {
		return new OmniSketchBuilder();
	}

	/** Heapifies a compact OmniSketch from a serialized byte array. */
	public static CompactOmniSketch heapify(final byte[] byteArray) {
		Objects.requireNonNull(byteArray, "Source byte array must not be null");
		return CompactOmniSketch.heapify(MemorySegment.ofArray(byteArray));
	}

	/** Heapifies a compact OmniSketch from a serialized MemorySegment image. */
	public static CompactOmniSketch heapify(final MemorySegment srcSeg) {
		return CompactOmniSketch.heapify(srcSeg);
	}

	/**
	 * Wraps a compact OmniSketch MemorySegment image for read-only access without copying all cells to the heap.
	 *
	 * <p>
	 * The caller owns the segment and must keep it alive and unchanged while the wrapped sketch is used.
	 * </p>
	 */
	public static CompactOmniSketch wrap(final MemorySegment srcSeg) {
		return CompactOmniSketch.wrap(srcSeg);
	}

	/** Returns a human-readable preamble summary of an OmniSketch byte-array image. */
	public static String toString(final byte[] byteArray) {
		Objects.requireNonNull(byteArray, "Source byte array must not be null");
		return PreambleUtil.preambleToString(MemorySegment.ofArray(byteArray));
	}

	/** Returns a human-readable preamble summary of an OmniSketch MemorySegment image. */
	public static String toString(final MemorySegment seg) {
		return PreambleUtil.preambleToString(seg);
	}

	/** Returns the local family descriptor for this sketch. */
	public final OmniSketchFamily getFamily() {
		return OmniSketchFamily.OMNI;
	}

	/** Returns lg(width), where width is the number of cells per row. */
	public abstract int getLgWidth();

	/** Returns the number of cells per row. */
	public final int getWidth() {
		return 1 << getLgWidth();
	}

	/** Returns the number of independent rows. */
	public abstract int getNumRows();

	/** Returns the number of identifier hashes retained by each cell. */
	public abstract int getNominalEntries();

	/** Returns the hash seed used for values, rows, and identifiers. */
	public abstract long getSeed();

	/** Returns the total number of updates applied to this sketch. */
	public abstract long getTotalUpdates();

	/** Returns the total number of retained identifier hashes across all cells. */
	public abstract int getRetainedEntries();

	/** Returns true if this sketch has received no updates. */
	public abstract boolean isEmpty();

	/** Returns true if this sketch is immutable and compact. */
	public abstract boolean isCompact();

	/** Returns the serialized byte size of this sketch in its current form. */
	public abstract int getCurrentBytes();

	/** Returns the serialized byte size of this sketch after compacting. */
	public abstract int getCompactBytes();

	/** Estimates the number of distinct identifiers in this dimension. */
	public final OmniSketchEstimate estimate() {
		return estimate(OmniSketchPredicate.all());
	}

	/** Returns {@link #estimate()} as a double. */
	public final double getEstimate() {
		return estimate().getEstimate();
	}

	/** Estimates the number of distinct identifiers equal to the given value. */
	public final OmniSketchEstimate estimate(final Object value) {
		return estimate(OmniSketchPredicate.equalTo(value));
	}

	/** Returns {@link #estimate(Object)} as a double. */
	public final double getEstimate(final Object value) {
		return estimate(value).getEstimate();
	}

	/** Estimates the number of distinct identifiers matching the given predicate over this dimension. */
	public abstract OmniSketchEstimate estimate(OmniSketchPredicate predicate);

	/** Returns an immutable compact representation on the Java heap. */
	public abstract CompactOmniSketch compact();

	/**
	 * Returns an immutable compact representation, optionally written to the supplied destination segment.
	 *
	 * @param dstSeg destination memory segment, or {@code null} for a heap compact sketch
	 * @return a compact sketch backed by {@code dstSeg} when non-null, otherwise a heap compact sketch
	 */
	public abstract CompactOmniSketch compact(MemorySegment dstSeg);

	/** Serializes this sketch to a compact byte array. */
	public abstract byte[] toByteArray();

	@Override
	public boolean hasMemorySegment() {
		return false;
	}

	@Override
	public boolean isOffHeap() {
		return false;
	}

	@Override
	public boolean isSameResource(final MemorySegment that) {
		return false;
	}

	final OmniSketchSummary summary(final OmniSketchPredicate predicate) {
		Objects.requireNonNull(predicate, "Predicate must not be null");
		if (predicate.isAll()) {
			return summaryAll();
		}
		final long[] hashes = predicate.valueHashes(getSeed());
		final List<OmniSketchSummary> summaries = new ArrayList<>(hashes.length);
		for (final long valueHash : hashes) {
			summaries.add(summaryForValueHash(valueHash));
		}
		return summaries.size() == 1 ? summaries.get(0) : OmniSketchSummary.union(summaries, getNominalEntries());
	}

	final OmniSketchSummary summaryForValueHash(final long valueHash) {
		final List<OmniSketchCell> rowCells = new ArrayList<>(getNumRows());
		for (int row = 0; row < getNumRows(); row++) {
			final int column = OmniSketchHash.indexFor(OmniSketchHash.rowHash(valueHash, row, getSeed()), getLgWidth());
			rowCells.add(getCell(row, column));
		}
		return OmniSketchSummary.fromCells(rowCells, getNominalEntries());
	}

	private OmniSketchSummary summaryAll() {
		final List<OmniSketchSummary> summaries = new ArrayList<>(getWidth());
		for (int column = 0; column < getWidth(); column++) {
			summaries.add(getCell(0, column).toSummary());
		}
		return OmniSketchSummary.union(summaries, getNominalEntries());
	}

	final void checkCompatible(final OmniSketch other) {
		Objects.requireNonNull(other, "Other sketch must not be null");
		if (getLgWidth() != other.getLgWidth() || getNumRows() != other.getNumRows()
				|| getNominalEntries() != other.getNominalEntries() || getSeed() != other.getSeed()) {
			throw new SketchesArgumentException("Incompatible OmniSketch configuration");
		}
	}

	abstract OmniSketchCell getCell(int row, int column);
}
